sql:
SELECT COUNT(*) AS num_matches_won
FROM matches
WHERE winner_clan_name = 'EnVyUs';

SELECT AVG(duration_seconds) AS average_duration
FROM matches
WHERE tournament_name = 'ESL One' AND winner_clan_name = 'EnVyUs';

SELECT COUNT(*) AS championships_won
FROM matches
WHERE winner_clan_name = 'Fnatic';

SELECT SUM(kills) AS total_kills
FROM players
WHERE player_name = 'Player2' AND side = 'T';

SELECT COUNT(*) AS total_winning_ct_matches
FROM matches
WHERE winner_side = 'CT';

SELECT AVG(duration_seconds) AS average_match_duration
FROM matches
WHERE winner_clan_name = 'AwesomeClan';

SELECT match_id
FROM matches
WHERE duration_seconds = (
    SELECT MAX(duration_seconds)
    FROM matches
);

SELECT COUNT(DISTINCT p.match_id) AS match_count
FROM players p
WHERE p.player_rank = 'Silver Nova';
